// ── Maison Beauté Newsletter — Format HTML Email ──────────────────
//
// Payload received from FastAPI /newsletter/generate:
//   subject_line  — AI-generated subject (use as-is, do NOT regenerate)
//   preview_text  — AI-generated preview text
//   body          — AI-generated body paragraphs (separated by \n\n)
//   cta           — AI-generated call-to-action sentence
//   new_products  — array of product name strings selected in Newsletter Studio
//   recipient     — destination email address
//
// Product cards are built by matching new_products names against PRODUCT_MAP.
// Images are served from raw.githubusercontent.com (public, no auth needed).

const payload = $input.first().json.body;

const subjectLine = payload.subject_line || 'Your Maison Beauté Newsletter';
const previewText = payload.preview_text || '';
const bodyText    = payload.body || '';
const ctaText     = payload.cta || 'Explore our curated collection today.';
const newProducts = payload.new_products || [];
const recipient   = payload.recipient || 'carolinanami@gmail.com';

// ── Product catalogue map ──────────────────────────────────────────
// Maps product name (as sent by FastAPI) → { sku, badge, imageUrl }
const PRODUCT_MAP = {
  "Lancôme Lip Idôle JuicyTreat": {
    sku: "WI-000002100",
    badge: "MAKE-UP",
    badgeColor: "#FCE8F3",
    badgeText: "#7C1D5A",
    imageUrl: "https://raw.githubusercontent.com/carolinanami-max/Final-Project-Maison-Beaute-Carolina-Nami/main/data/images/WI-000002100.jpg"
  },
  "La Mer The Treatment Lotion": {
    sku: "WI-000000148",
    badge: "SKIN-CARE",
    badgeColor: "#E3F3FF",
    badgeText: "#1A5C87",
    imageUrl: "https://raw.githubusercontent.com/carolinanami-max/Final-Project-Maison-Beaute-Carolina-Nami/main/data/images/WI-000000148.jpg"
  },
  "U Beauty Resurfacing Compound": {
    sku: "WI-000000440",
    badge: "SKIN-CARE",
    badgeColor: "#E3F3FF",
    badgeText: "#1A5C87",
    imageUrl: "https://raw.githubusercontent.com/carolinanami-max/Final-Project-Maison-Beaute-Carolina-Nami/main/data/images/WI-000000440.jpg"
  }
};

// ── Build body paragraphs from \n\n-separated text ────────────────
const paragraphs = bodyText
  .split('\n\n')
  .map(p => p.trim())
  .filter(p => p.length > 0)
  .map(p => `<p style="margin:0 0 16px 0;font-size:15px;line-height:1.75;color:#3A2A4A">${p.replace(/\n/g, '<br>')}</p>`)
  .join('\n');

// ── Build product cards ────────────────────────────────────────────
const productCardsHtml = newProducts.length > 0
  ? newProducts.map(name => {
      const product = PRODUCT_MAP[name];
      if (!product) return '';
      return `
      <table role="presentation" cellpadding="0" cellspacing="0" style="width:100%;margin-bottom:12px;background:#FAFAFA;border-radius:8px;border:1px solid #EDE8E3">
        <tr>
          <td style="width:70px;padding:12px 0 12px 14px;vertical-align:middle">
            <img src="${product.imageUrl}" alt="${name}" width="58" height="58"
              style="border-radius:6px;object-fit:cover;display:block"
              onerror="this.style.display='none'">
          </td>
          <td style="padding:12px 8px;vertical-align:middle">
            <span style="display:inline-block;background:${product.badgeColor};color:${product.badgeText};font-size:10px;font-weight:600;letter-spacing:0.08em;padding:2px 8px;border-radius:10px;margin-bottom:4px">${product.badge}</span><br>
            <span style="font-family:'Georgia',serif;font-size:14px;font-weight:600;color:#1A1A2E">${name}</span><br>
            <span style="font-size:11px;color:#9B8FA0;margin-top:2px;display:inline-block">${product.sku}</span>
          </td>
          <td style="padding:12px 14px 12px 0;vertical-align:middle;text-align:right;white-space:nowrap">
            <a href="https://maisonbeaute.de" style="font-size:12px;color:#C9748F;font-weight:600;text-decoration:none">View product →</a>
          </td>
        </tr>
      </table>`;
    }).join('\n')
  : '';

// ── Assemble full HTML email ───────────────────────────────────────
const htmlEmail = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
  <meta name="x-apple-disable-message-reformatting">
  <title>${subjectLine}</title>
  <!--[if mso]><noscript><xml><o:OfficeDocumentSettings><o:PixelsPerInch>96</o:PixelsPerInch></o:OfficeDocumentSettings></xml></noscript><![endif]-->
  <style>
    body { margin:0;padding:0;background:#F8F5F2;-webkit-text-size-adjust:100% }
    @media only screen and (max-width:600px) {
      .email-container { width:100%!important }
      .hero-title { font-size:26px!important }
    }
  </style>
</head>
<body style="background:#F8F5F2;margin:0;padding:0">

  <!-- Preheader (hidden preview text) -->
  <div style="display:none;max-height:0;overflow:hidden;font-size:1px;color:#F8F5F2">
    ${previewText}&nbsp;‌&nbsp;‌&nbsp;‌&nbsp;‌&nbsp;‌&nbsp;‌&nbsp;‌&nbsp;‌&nbsp;‌
  </div>

  <!-- Outer wrapper -->
  <table role="presentation" cellpadding="0" cellspacing="0" style="width:100%;background:#F8F5F2">
    <tr>
      <td align="center" style="padding:32px 16px">

        <!-- Email container -->
        <table class="email-container" role="presentation" cellpadding="0" cellspacing="0"
          style="width:600px;max-width:600px;background:#FFFFFF;border-radius:12px;overflow:hidden;box-shadow:0 4px 24px rgba(26,26,46,0.10)">

          <!-- ── HEADER ── -->
          <tr>
            <td style="background:linear-gradient(135deg,#1A1A2E 0%,#2D1B4E 100%);padding:36px 40px 28px;text-align:center">
              <p style="margin:0 0 6px;font-family:'Georgia',serif;font-size:11px;color:#C9748F;letter-spacing:0.28em;text-transform:uppercase">Maison Beauté</p>
              <h1 class="hero-title" style="margin:0;font-family:'Georgia',serif;font-size:30px;font-weight:400;color:#F2E8D9;line-height:1.2;letter-spacing:0.02em">${subjectLine}</h1>
              <p style="margin:14px 0 0;font-family:Arial,sans-serif;font-size:13px;color:rgba(242,232,217,0.6);font-style:italic">${previewText}</p>
            </td>
          </tr>

          <!-- ── BODY ── -->
          <tr>
            <td style="padding:36px 40px 0">
              ${paragraphs}
            </td>
          </tr>

          ${productCardsHtml ? `
          <!-- ── PRODUCT CARDS ── -->
          <tr>
            <td style="padding:8px 40px 0">
              <p style="font-family:Arial,sans-serif;font-size:10px;font-weight:600;letter-spacing:0.18em;text-transform:uppercase;color:#9B8FA0;margin:0 0 12px">Featured Arrivals</p>
              ${productCardsHtml}
            </td>
          </tr>` : ''}

          <!-- ── CTA BUTTON ── -->
          <tr>
            <td style="padding:32px 40px;text-align:center">
              <a href="https://maisonbeaute.de"
                style="display:inline-block;background:linear-gradient(135deg,#1A1A2E,#2D1B4E);color:#F2E8D9;font-family:Arial,sans-serif;font-size:14px;font-weight:600;letter-spacing:0.08em;text-decoration:none;padding:14px 36px;border-radius:4px">
                ${ctaText}
              </a>
            </td>
          </tr>

          <!-- ── DIVIDER ── -->
          <tr>
            <td style="padding:0 40px">
              <hr style="border:none;border-top:1px solid #E8E0DC;margin:0">
            </td>
          </tr>

          <!-- ── FOOTER ── -->
          <tr>
            <td style="padding:24px 40px 32px;text-align:center">
              <p style="margin:0 0 6px;font-family:Arial,sans-serif;font-size:11px;color:#B0A4B8">
                Maison Beauté · Pre-Loved Luxury Beauty · Berlin
              </p>
              <p style="margin:0 0 6px;font-family:Arial,sans-serif;font-size:11px;color:#B0A4B8">
                <a href="https://maisonbeaute.de" style="color:#C9748F;text-decoration:none">Shop</a> &nbsp;·&nbsp;
                <a href="https://maisonbeaute.de/privacy" style="color:#C9748F;text-decoration:none">Privacy</a> &nbsp;·&nbsp;
                <a href="https://maisonbeaute.de/unsubscribe" style="color:#C9748F;text-decoration:none">Unsubscribe</a>
              </p>
              <p style="margin:8px 0 0;font-family:Arial,sans-serif;font-size:10px;color:#C9C0CE">
                © 2026 Maison Beauté. All rights reserved. GDPR compliant · EU AI Act: Limited Risk (Art. 50)
              </p>
            </td>
          </tr>

        </table>
        <!-- /email container -->

      </td>
    </tr>
  </table>

</body>
</html>`;

return [
  {
    json: {
      html: htmlEmail,
      subject: subjectLine,
      recipient: recipient
    }
  }
];
